const sd=$getWorkflowStaticData('global');

const executionId=String($execution.id ?? 'manual');
const TZ='America/Sao_Paulo';
const now=new Date();
const nowIso=now.toISOString();
const parts=new Intl.DateTimeFormat('en-CA',{
  timeZone:TZ,
  year:'numeric',
  month:'2-digit',
  day:'2-digit'
}).formatToParts(now);
const m={};
for(const p of parts){
  m[p.type]=p.value;
}

const year=Number(m.year);
const month=Number(m.month);
const day=Number(m.day);
let compYear=year;
let compMonth=month-1;
if(compMonth===0){
  compMonth=12;
  compYear=year-1;
}

const mm=String(compMonth).padStart(2,'0');
const competenciaYMD=compYear+'-'+mm+'-01';
const daysInCompMonth=new Date(Date.UTC(compYear,compMonth,0)).getUTCDate();
const compStart=competenciaYMD;
const compEnd=compYear+'-'+mm+'-'+String(daysInCompMonth).padStart(2,'0');

const metrics={"rulesPages":0,"rulesTotal":0,"rulesEligible":0,"rulesIneligible":0,"rulesInvalid":0,"rulesSkippedDay":0,"rulesSkippedExisting":0,"invoicesPrefetchCalls":0,"invoicesPrefetchCount":0,"prefetchInvoicesMissingRuleLink":0,"itemBatchQueries":0,"itemsFetched":0,"createInvoices":0,"createItems":0,"updateItemInvoiceLinks":0,"updateParcelasPagas":0,"unexpectedStateErrors":0};

const runContext={
  executionId,
  startedAt:nowIso,
  timezone:TZ,
  todayDay:day,
  competenciaYMD,
  compStart,
  compEnd,
  flags:{
    maxRulesPages:50,
    maxPrefetchPages:50,
    rulesPageSize:50,
    prefetchPageSize:200
  },
  metrics,
  logs:[],
  errors:[]
};

sd.finV3Runs=(sd.finV3Runs && typeof sd.finV3Runs==='object' && !Array.isArray(sd.finV3Runs)) ? sd.finV3Runs : {};
for(const [key,state] of Object.entries(sd.finV3Runs)){
  const startedAt=state?.runInit?.startedAt || null;
  const ageMs=startedAt ? (Date.now()-Date.parse(startedAt)) : Number.POSITIVE_INFINITY;
  if(!Number.isFinite(ageMs) || ageMs > 24*60*60*1000){
    delete sd.finV3Runs[key];
  }
}

sd.finV3Runs[executionId]={
  runInit:{
    executionId,
    startedAt:runContext.startedAt,
    competenciaYMD:runContext.competenciaYMD,
    metrics:{...runContext.metrics}
  },
  acc:{
    contractVersion:'fin_v3',
    metrics:{...runContext.metrics},
    failures:[],
    results:[],
    statusCounts:{processed:0,skipped:0,failed:0},
    skippedReasons:{},
    prepSummarySeen:false,
    prepSummaryCount:0,
    ruleResultsReceived:0,
    malformedResults:0
  }
};

return [{json:{runContext}}];

const sd=$getWorkflowStaticData('global');
const executionId=String($execution.id ?? 'manual');

sd.finV3Runs=(sd.finV3Runs && typeof sd.finV3Runs==='object' && !Array.isArray(sd.finV3Runs)) ? sd.finV3Runs : {};
if(!sd.finV3Runs[executionId]){
  sd.finV3Runs[executionId]={
    runInit:{executionId,startedAt:new Date().toISOString(),competenciaYMD:null,metrics:{}},
    acc:{
      contractVersion:'fin_v3',
      metrics:{},
      failures:[],
      results:[],
      statusCounts:{processed:0,skipped:0,failed:0},
      skippedReasons:{},
      prepSummarySeen:false,
      prepSummaryCount:0,
      ruleResultsReceived:0,
      malformedResults:0
    }
  };
}

const state=sd.finV3Runs[executionId];
const acc=state.acc;
const allowedStatus=new Set(['processed','skipped','failed']);
const collectIds=(...values)=>{
  const out=[];
  const visit=(value)=>{
    if(value===undefined || value===null) return;
    if(Array.isArray(value)){
      for(const item of value) visit(item);
      return;
    }
    const s=String(value).trim();
    if(s) out.push(s);
  };
  for(const value of values) visit(value);
  return Array.from(new Set(out));
};
const normalizeFailure=(failure,fallbackReason,...extraIds)=>({
  node:String(failure?.node || 'Accumulate results'),
  reason:String(failure?.reason || fallbackReason || 'unexpected_payload_shape'),
  pipefyCardIds:collectIds(failure?.pipefyCardIds, extraIds)
});
const pushSyntheticFailure=(reason,...ids)=>{
  acc.failures.push({
    node:'Accumulate results',
    reason:String(reason || 'unexpected_payload_shape'),
    pipefyCardIds:collectIds(...ids)
  });
};

for(const it of $input.all()){
  const j=(it && it.json && typeof it.json==='object' && !Array.isArray(it.json)) ? it.json : {};
  const rule=(j.rule && typeof j.rule==='object' && !Array.isArray(j.rule)) ? j.rule : {};
  const res=(j.result && typeof j.result==='object' && !Array.isArray(j.result)) ? j.result : {};
  const fallbackIds=collectIds(rule.ruleId ?? null, res.invoiceId ?? null, res.existingInvoiceId ?? null, res.createdItemIds ?? null);

  if(String(j.contractVersion || '')!=='fin_v3'){
    acc.malformedResults += 1;
    pushSyntheticFailure('invalid_contract_version', fallbackIds);
    continue;
  }

  const itemType=String(j.itemType || '');
  if(itemType==='prep_summary'){
    acc.prepSummarySeen=true;
    acc.prepSummaryCount=Number(acc.prepSummaryCount || 0) + 1;
    const prepMetrics=(res.metrics && typeof res.metrics==='object' && !Array.isArray(res.metrics))
      ? res.metrics
      : ((res.prepContext?.metrics && typeof res.prepContext.metrics==='object' && !Array.isArray(res.prepContext.metrics)) ? res.prepContext.metrics : {});
    for(const [k,v] of Object.entries(prepMetrics)){
      const n=Number(v);
      if(Number.isFinite(n)){
        acc.metrics[k]=n;
      }
    }
    const prepFailures=Array.isArray(res.failures) ? res.failures : [];
    for(const failure of prepFailures){
      acc.failures.push(normalizeFailure(failure, 'unexpected_payload_shape', fallbackIds));
    }
    continue;
  }

  if(itemType!=='rule_result'){
    acc.malformedResults += 1;
    pushSyntheticFailure('unexpected_item_type', fallbackIds);
    continue;
  }

  let status=String(res.status || 'failed');
  let reason=String(res.reason || 'unexpected_payload_shape');
  if(!allowedStatus.has(status)){
    status='failed';
    reason='unexpected_payload_shape';
    acc.malformedResults += 1;
  }

  if(res.metricsDelta && typeof res.metricsDelta==='object' && !Array.isArray(res.metricsDelta)){
    for(const [k,v] of Object.entries(res.metricsDelta)){
      const n=Number(v);
      if(Number.isFinite(n)){
        acc.metrics[k]=(Number(acc.metrics[k]) || 0) + n;
      }
    }
  }

  const normalizedFailures=[];
  const incomingFailures=Array.isArray(res.failures) ? res.failures : [];
  for(const failure of incomingFailures){
    normalizedFailures.push(normalizeFailure(failure, reason, fallbackIds));
  }
  if(status==='failed' && normalizedFailures.length===0){
    normalizedFailures.push({
      node:'Accumulate results',
      reason,
      pipefyCardIds:fallbackIds
    });
  }
  if(normalizedFailures.length>0){
    acc.failures.push(...normalizedFailures);
  }

  const createdCount=Array.isArray(res.createdItemIds) ? res.createdItemIds.length : 0;

  acc.ruleResultsReceived += 1;
  acc.statusCounts[status]=Number(acc.statusCounts[status] || 0) + 1;
  if(status==='skipped'){
    acc.skippedReasons[reason]=Number(acc.skippedReasons[reason] || 0) + 1;
  }

  acc.results.push({
    ruleId:rule.ruleId ?? null,
    status,
    reason,
    invoiceId:res.invoiceId ?? null,
    existingInvoiceId:res.existingInvoiceId ?? null,
    createdCount,
    timings:res.timings ?? null,
    prefetchDecision:rule.prefetchDecision ?? null,
    failureCount:normalizedFailures.length
  });
}

return $input.all();

const sd=$getWorkflowStaticData('global');
const executionId=String($execution.id ?? 'manual');

sd.finV3Runs=(sd.finV3Runs && typeof sd.finV3Runs==='object' && !Array.isArray(sd.finV3Runs)) ? sd.finV3Runs : {};
const state=sd.finV3Runs[executionId];

const defaults={"rulesPages":0,"rulesTotal":0,"rulesEligible":0,"rulesIneligible":0,"rulesInvalid":0,"rulesSkippedDay":0,"rulesSkippedExisting":0,"invoicesPrefetchCalls":0,"invoicesPrefetchCount":0,"prefetchInvoicesMissingRuleLink":0,"itemBatchQueries":0,"itemsFetched":0,"createInvoices":0,"createItems":0,"updateItemInvoiceLinks":0,"updateParcelasPagas":0,"unexpectedStateErrors":0};

const runInit=(state?.runInit && typeof state.runInit==='object' && !Array.isArray(state.runInit)) ? state.runInit : {executionId,startedAt:null,competenciaYMD:null,metrics:{...defaults}};
const acc=(state?.acc && typeof state.acc==='object' && !Array.isArray(state.acc)) ? state.acc : {
  contractVersion:'fin_v3',
  metrics:{...defaults},
  failures:[],
  results:[],
  statusCounts:{processed:0,skipped:0,failed:0},
  skippedReasons:{},
  prepSummarySeen:false,
  prepSummaryCount:0,
  ruleResultsReceived:0,
  malformedResults:0
};

const metrics={...defaults};
if(runInit.metrics && typeof runInit.metrics==='object' && !Array.isArray(runInit.metrics)){
  for(const [k,v] of Object.entries(runInit.metrics)){
    const n=Number(v);
    if(Number.isFinite(n)) metrics[k]=n;
  }
}
if(acc.metrics && typeof acc.metrics==='object' && !Array.isArray(acc.metrics)){
  for(const [k,v] of Object.entries(acc.metrics)){
    const n=Number(v);
    if(Number.isFinite(n)) metrics[k]=n;
  }
}

const sc={processed:0,skipped:0,failed:0,...(acc.statusCounts || {})};
const processedRules=Number(sc.processed || 0);
const skippedRules=Number(sc.skipped || 0);
const failedRules=Number(sc.failed || 0);
const failures=Array.isArray(acc.failures) ? acc.failures : [];
const ruleResultsReceived=Number(acc.ruleResultsReceived || 0);
const malformedResults=Number(acc.malformedResults || 0);
const prepSummarySeen=Boolean(acc.prepSummarySeen);
const prepSummaryCount=Number(acc.prepSummaryCount || 0);

const failedNodes={};
const failedReasons={};
const pipefyCardIds=[];
const pipefyCardSet=new Set();
for(const failure of failures){
  const node=String(failure?.node || 'Accumulate results');
  const reason=String(failure?.reason || 'unexpected_payload_shape');
  failedNodes[node]=Number(failedNodes[node] || 0) + 1;
  failedReasons[reason]=Number(failedReasons[reason] || 0) + 1;
  const ids=Array.isArray(failure?.pipefyCardIds) ? failure.pipefyCardIds : [];
  for(const rawId of ids){
    const id=String(rawId || '').trim();
    if(!id || pipefyCardSet.has(id)) continue;
    pipefyCardSet.add(id);
    pipefyCardIds.push(id);
  }
}

const expectedRuleResults=Number(metrics.rulesTotal || 0);
const integrityErrors=[];
if(!prepSummarySeen){
  integrityErrors.push('prep_summary_missing');
}
if(expectedRuleResults>0 && ruleResultsReceived!==expectedRuleResults){
  integrityErrors.push('rule_results_mismatch_expected');
}

const startedAt=runInit.startedAt || null;
const finishedAt=new Date().toISOString();
const startedMs=Date.parse(startedAt || '');
const finishedMs=Date.parse(finishedAt);
const durationMs=(Number.isFinite(startedMs) && Number.isFinite(finishedMs)) ? Math.max(0,finishedMs-startedMs) : null;
const failureCount=failures.length;

const summary={
  contractVersion:'fin_v3',
  executionId,
  competenciaYMD:runInit.competenciaYMD || null,
  startedAt,
  finishedAt,
  durationMs,
  processedRules,
  skippedRules,
  failedRules,
  totalRules:processedRules+skippedRules+failedRules,
  ruleResultsReceived,
  expectedRuleResults,
  prepSummarySeen,
  prepSummaryCount,
  malformedResults,
  errorsCount:failureCount,
  failureCount,
  skippedReasons:(acc.skippedReasons && typeof acc.skippedReasons==='object' && !Array.isArray(acc.skippedReasons)) ? acc.skippedReasons : {},
  failedNodes,
  failedReasons,
  pipefyCardIds,
  integrityErrors,
  metrics
};

const ok=(failedRules===0) && (summary.failureCount===0) && (summary.malformedResults===0) && integrityErrors.length===0;

const run={
  contractVersion:'fin_v3',
  metrics,
  failures,
  results:Array.isArray(acc.results) ? acc.results : [],
  statusCounts:sc,
  skippedReasons:summary.skippedReasons,
  failedNodes,
  failedReasons,
  malformedResults,
  prepSummarySeen,
  prepSummaryCount,
  ruleResultsReceived,
  failureCount
};

if(sd.finV3Runs && sd.finV3Runs[executionId]){
  delete sd.finV3Runs[executionId];
}

return [{json:{summary,run,ok}}];
